'use client';

import { useMemo } from 'react';
import { useSelector } from 'react-redux';
import { RootState } from '@/store';
import { 
  BarChart3, PieChart, TrendingUp, Map, Clock, 
  ArrowUpRight, ArrowDownRight, Zap, Target
} from 'lucide-react';
import { motion } from 'framer-motion';
import { cn } from '@/lib/utils';

export default function AnalyticsPage() {
  const { trips } = useSelector((state: RootState) => state.trips);

  const stats = useMemo(() => {
    const totalDistance = trips.reduce((acc, t) => acc + (t.distance || 0), 0);
    const totalDuration = trips.reduce((acc, t) => acc + (t.duration || 0), 0);
    const avgDistance = trips.length > 0 ? totalDistance / trips.length : 0;

    const modeCounts = trips.reduce((acc, t) => {
      const mode = t.predictedMode || 'unknown';
      acc[mode] = (acc[mode] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);

    return { totalDistance, totalDuration, avgDistance, modeCounts };
  }, [trips]);

  const cards = [
    { label: 'Weekly Growth', value: '+12.5%', icon: TrendingUp, color: 'text-emerald-500', trend: 'up' },
    { label: 'Avg Speed', value: '24.2 km/h', icon: Zap, color: 'text-amber-500', trend: 'down' },
    { label: 'Eco Score', value: '82/100', icon: Target, color: 'text-indigo-500', trend: 'up' },
  ];

  return (
    <div className="p-6 lg:p-10 max-w-6xl mx-auto space-y-10">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-3xl font-bold text-slate-800 mb-1 font-sans">Smart Insights</h1>
          <p className="text-slate-500 font-medium">Predictive analytics based on your movement patterns</p>
        </div>
        <div className="flex gap-2 bg-white p-1 rounded-2xl border border-slate-200">
           <button className="px-4 py-2 bg-slate-900 text-white rounded-xl text-xs font-bold uppercase tracking-widest">Weekly</button>
           <button className="px-4 py-2 text-slate-400 hover:text-slate-600 rounded-xl text-xs font-bold uppercase tracking-widest transition-colors">Monthly</button>
        </div>
      </div>

      {/* Hero Stats */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {cards.map((card, i) => (
          <motion.div
            key={card.label}
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: i * 0.1 }}
            className="bg-white p-8 rounded-[2rem] border border-slate-200 shadow-sm relative overflow-hidden group"
          >
             <div className={cn("w-12 h-12 rounded-2xl flex items-center justify-center mb-6 bg-slate-50", card.color)}>
                <card.icon className="w-6 h-6" />
             </div>
             <p className="text-xs font-bold text-slate-400 uppercase tracking-[0.2em] mb-2">{card.label}</p>
             <div className="flex items-end gap-3">
                <span className="text-3xl font-black text-slate-800">{card.value}</span>
                <span className={cn(
                  "flex items-center text-xs font-bold mb-1",
                  card.trend === 'up' ? "text-emerald-500" : "text-rose-500"
                )}>
                  {card.trend === 'up' ? <ArrowUpRight className="w-4 h-4" /> : <ArrowDownRight className="w-4 h-4" />}
                  2.4%
                </span>
             </div>
             <div className="absolute -right-4 -bottom-4 opacity-[0.03] group-hover:scale-110 transition-transform">
                <card.icon className="w-32 h-32" />
             </div>
          </motion.div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Mode Distribution */}
        <section id="mode-split-section" className="bg-white p-10 rounded-[2.5rem] border border-slate-200 shadow-sm space-y-8">
           <div className="flex items-center justify-between">
              <h2 className="text-xl font-bold text-slate-800 flex items-center gap-3">
                 <PieChart className="w-6 h-6 text-indigo-500" /> Mode Split
              </h2>
           </div>

           <div className="space-y-6">
              {Object.entries(stats.modeCounts).map(([mode, count]) => (
                <div key={mode} className="space-y-2">
                   <div className="flex justify-between items-center text-sm font-bold">
                      <span className="capitalize text-slate-700">{mode.replace('_', ' ')}</span>
                      <span className="text-slate-400">{Math.round((count / trips.length) * 100)}%</span>
                   </div>
                   <div className="h-2 w-full bg-slate-50 rounded-full overflow-hidden">
                      <motion.div 
                        initial={{ width: 0 }}
                        animate={{ width: `${(count / trips.length) * 100}%` }}
                        className={cn(
                          "h-full rounded-full",
                          mode === 'walking' && "bg-emerald-400",
                          mode === 'cycling' && "bg-amber-400",
                          mode === 'driving' && "bg-indigo-500",
                          mode === 'public_transport' && "bg-purple-500"
                        )} 
                      />
                   </div>
                </div>
              ))}
              {Object.keys(stats.modeCounts).length === 0 && (
                <p className="text-center text-slate-400 py-10 font-medium italic">Track more trips to see analysis...</p>
              )}
           </div>
        </section>

        {/* Temporal Trends */}
        <section className="bg-slate-900 p-10 rounded-[2.5rem] text-white space-y-8 relative overflow-hidden">
           <h2 className="text-xl font-bold flex items-center gap-3">
              <Clock className="w-6 h-6 text-indigo-400" /> Activity Hours
           </h2>
           <div className="flex items-end justify-between h-48 gap-2 pt-10">
              {[40, 70, 45, 90, 65, 80, 55, 60, 40, 30, 20, 10].map((h, i) => (
                <motion.div 
                  key={i}
                  initial={{ height: 0 }}
                  animate={{ height: `${h}%` }}
                  className="w-full bg-indigo-500/20 rounded-t-lg group relative"
                >
                   <div className="absolute inset-0 bg-indigo-400 scale-x-0 group-hover:scale-x-100 transition-transform origin-bottom rounded-t-lg" />
                </motion.div>
              ))}
           </div>
           <div className="flex justify-between text-[10px] font-black text-white/20 uppercase tracking-widest">
              <span>06:00</span>
              <span>12:00</span>
              <span>18:00</span>
              <span>00:00</span>
           </div>
           <p className="text-xs text-indigo-300 font-bold bg-indigo-500/10 p-4 rounded-2xl border border-indigo-500/20">
              =ƒÆí Peak activity detected between 08:30 and 10:00. Commute patterns confirmed.
           </p>
        </section>
      </div>

      {/* Carbon Impact Section */}
      <section className="bg-indigo-600 p-12 rounded-[3rem] text-white flex flex-col md:flex-row items-center gap-12 relative overflow-hidden shadow-2xl shadow-indigo-200">
         <div className="flex-1 space-y-6 relative z-10 text-center md:text-left">
            <h2 className="text-4xl font-black">Environmental Impact</h2>
            <p className="text-indigo-100 text-lg font-medium max-w-lg">
               By using eco-friendly travel modes (walking/cycling), you've saved approximately 
               <span className="text-white font-black underline decoration-indigo-300 decoration-4 underline-offset-8 mx-2">
                 {(stats.totalDistance * 0.12).toFixed(1)} kg
               </span>
               of CO2 emissions this month.
            </p>
             <div className="flex justify-center md:justify-start">
                <button 
                  onClick={() => document.getElementById('mode-split-section')?.scrollIntoView({ behavior: 'smooth' })}
                  className="bg-white text-indigo-600 px-8 py-4 rounded-2xl font-black shadow-lg shadow-indigo-800/20 hover:scale-105 transition-transform uppercase tracking-widest text-sm"
                >
                   Full Eco Report
                </button>
             </div>
         </div>
         <div className="relative">
            <div className="w-48 h-48 bg-white/10 rounded-full flex items-center justify-center backdrop-blur-3xl border border-white/20 animate-pulse">
               <TrendingUp className="w-20 h-20 text-white" />
            </div>
            <div className="absolute top-0 right-0 w-12 h-12 bg-emerald-400 rounded-full flex items-center justify-center border-4 border-indigo-600 rotate-12">
               <Zap className="w-6 h-6 text-indigo-900" />
            </div>
         </div>
         <BarChart3 className="absolute -left-10 -bottom-10 w-64 h-64 text-white/5 pointer-events-none" />
      </section>
    </div>
  );
}

'use client';

import { useState, useMemo } from 'react';
import { useSelector } from 'react-redux';
import { RootState } from '@/store';
import { Search, MapPin, Clock, Calendar, ArrowRight, Filter } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { cn } from '@/lib/utils';
import Link from 'next/link';

export default function HistoryPage() {
  const { trips } = useSelector((state: RootState) => state.trips);
  const [searchQuery, setSearchQuery] = useState('');
  const [filterMode, setFilterMode] = useState<string | 'all'>('all');

  const filteredTrips = useMemo(() => {
    return trips.filter(trip => {
      const matchesSearch = 
        trip.predictedMode?.toLowerCase().includes(searchQuery.toLowerCase()) ||
        new Date(trip.startTime).toLocaleDateString().toLowerCase().includes(searchQuery.toLowerCase());

      const matchesFilter = filterMode === 'all' || trip.predictedMode === filterMode;

      return matchesSearch && matchesFilter;
    });
  }, [trips, searchQuery, filterMode]);

  const modes = ['all', 'walking', 'cycling', 'driving', 'public_transport'];

  return (
    <div className="p-6 lg:p-10 max-w-5xl mx-auto">
      <div className="mb-10">
        <h1 className="text-3xl font-bold text-slate-800 mb-2">Trip History</h1>
        <p className="text-slate-500">Review your past journeys and AI classifications</p>
      </div>

      {/* Search and Filter */}
      <div className="flex flex-col md:flex-row gap-4 mb-8">
        <div className="relative flex-1">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
          <input
            type="text"
            placeholder="Search by date or mode..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full bg-white border border-slate-200 rounded-2xl py-3 pl-12 pr-4 focus:outline-none focus:ring-2 focus:ring-indigo-500/20 transition-all shadow-sm"
          />
        </div>
        <div className="flex gap-2 p-1 bg-slate-100 rounded-2xl overflow-x-auto">
          {modes.map((mode) => (
            <button
              key={mode}
              onClick={() => setFilterMode(mode)}
              className={cn(
                "px-4 py-2 rounded-xl text-sm font-bold capitalize whitespace-nowrap transition-all",
                filterMode === mode 
                  ? "bg-white text-indigo-600 shadow-sm" 
                  : "text-slate-500 hover:text-slate-700"
              )}
            >
              {mode.replace('_', ' ')}
            </button>
          ))}
        </div>
      </div>

      {/* List */}
      <div className="space-y-4">
        <AnimatePresence mode="popLayout">
          {filteredTrips.length === 0 ? (
            <motion.div 
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              className="text-center py-20 bg-white rounded-3xl border border-slate-200 border-dashed"
            >
              <div className="bg-slate-50 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4">
                <Search className="text-slate-300 w-8 h-8" />
              </div>
              <p className="text-slate-400 font-medium">No trips found matching your criteria.</p>
            </motion.div>
          ) : (
            filteredTrips.map((trip) => (
              <Link
                key={trip.id}
                href={`/trip/${trip.id}`}
                className="block group"
              >
                <motion.div
                  layout
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0, scale: 0.95 }}
                  className="bg-white p-6 rounded-3xl border border-slate-200 hover:border-indigo-200 hover:shadow-xl hover:shadow-indigo-500/5 transition-all cursor-pointer flex flex-col md:flex-row md:items-center gap-6"
                >
                  <div className="flex items-center gap-6 flex-1">
                    <div className="w-16 h-16 bg-slate-50 rounded-2xl flex items-center justify-center text-3xl group-hover:bg-indigo-50 transition-colors shrink-0">
                      {trip.predictedMode === 'walking' && "=ƒÜ¦"}
                      {trip.predictedMode === 'cycling' && "=ƒÜ¦"}
                      {trip.predictedMode === 'driving' && "=ƒÜù"}
                      {trip.predictedMode === 'public_transport' && "=ƒÜî"}
                      {(!trip.predictedMode || trip.predictedMode === 'unknown') && "=ƒôì"}
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-3 mb-1">
                        <h3 className="font-bold text-slate-800 text-lg capitalize">{trip.predictedMode || 'Unknown Journey'}</h3>
                        {trip.distance! > 5 && (
                          <span className="bg-amber-50 text-amber-600 text-[10px] font-black uppercase tracking-widest px-2 py-0.5 rounded-full border border-amber-100">Long Distance</span>
                        )}
                      </div>
                      <div className="flex flex-wrap items-center gap-x-6 gap-y-2 text-sm text-slate-500 font-medium">
                        <span className="flex items-center gap-2">
                          <Calendar className="w-4 h-4 text-slate-400" />
                          {new Date(trip.startTime).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' })}
                        </span>
                        <span className="flex items-center gap-2">
                          <Clock className="w-4 h-4 text-slate-400" />
                          {(trip.duration! / 60000).toFixed(0)} minutes
                        </span>
                        <span className="flex items-center gap-2 font-bold text-slate-700">
                          <MapPin className="w-4 h-4 text-indigo-500" />
                          {trip.distance?.toFixed(2)} km
                        </span>
                      </div>
                    </div>
                  </div>

                  <div className="flex items-center justify-between md:justify-end gap-4 border-t md:border-t-0 pt-4 md:pt-0 border-slate-50">
                     <div className="text-right hidden sm:block">
                        <p className="text-[10px] font-black text-slate-300 uppercase tracking-widest mb-0.5">Confidence</p>
                        <div className="flex gap-1">
                          {[1, 2, 3, 4, 5].map((i) => (
                            <div key={i} className={cn("w-3 h-1 rounded-full", i <= 4 ? "bg-emerald-400" : "bg-slate-100")} />
                          ))}
                        </div>
                     </div>
                     <div className="bg-slate-50 group-hover:bg-indigo-600 p-2 rounded-full transition-all">
                        <ArrowRight className="w-5 h-5 text-slate-400 group-hover:text-white transition-colors" />
                     </div>
                  </div>
                </motion.div>
              </Link>
            ))
          )}
        </AnimatePresence>
      </div>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { RootState } from '@/store';
import { startTrip, stopTrip, addPoint } from '@/store/slices/tripSlice';
import { signInAnonymously } from '@/store/slices/authSlice';
import { Play, Square, MapPin, Navigation, History, User, Activity, Clock, CheckCircle } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import Link from 'next/link';
import { cn } from '@/lib/utils';

export default function Home() {
  const dispatch = useDispatch();
  const { isTracking, currentTrip, trips } = useSelector((state: RootState) => state.trips);
  const { isAuthenticated, user } = useSelector((state: RootState) => state.auth);
  const [duration, setDuration] = useState(0);
  const [showStopConfirmation, setShowStopConfirmation] = useState(false);

  useEffect(() => {
    let interval: NodeJS.Timeout;
    if (isTracking && currentTrip) {
      interval = setInterval(() => {
        setDuration(Math.floor((Date.now() - currentTrip.startTime) / 1000));

        // Simulate movement for demo purposes if no real GPS
        // In reality, we'd use navigator.geolocation
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [isTracking, currentTrip]);

  const handleStart = () => {
    if (!isAuthenticated) {
      dispatch(signInAnonymously() as any);
    }

    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition((position) => {
        const point = {
          latitude: position.coords.latitude,
          longitude: position.coords.longitude,
          timestamp: position.timestamp,
          accuracy: position.coords.accuracy || 0,
          speed: position.coords.speed || 0,
        };
        dispatch(startTrip(point) as any);

        // Start watching
        navigator.geolocation.watchPosition((pos) => {
          dispatch(addPoint({
            latitude: pos.coords.latitude,
            longitude: pos.coords.longitude,
            timestamp: pos.timestamp,
            accuracy: pos.coords.accuracy || 0,
            speed: pos.coords.speed || 0,
          }));
        });
      });
    } else {
      alert("Geolocation not supported");
    }
  };

  const handleStop = () => {
    if (showStopConfirmation) {
      dispatch(stopTrip() as any);
      setShowStopConfirmation(false);
    } else {
      setShowStopConfirmation(true);
    }
  };

  const formatDuration = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="min-h-full text-slate-900 font-sans">
      <main className="max-w-6xl mx-auto p-6 grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Tracking Card */}
        <div className="lg:col-span-2 space-y-8">
          <section className="bg-white rounded-3xl shadow-sm border border-slate-200 overflow-hidden relative">
            <div className={`h-2 ${isTracking ? 'bg-emerald-500' : 'bg-slate-200'} transition-all`} />
            <div className="p-8">
              <div className="flex justify-between items-start mb-8">
                <div>
                  <h2 className="text-2xl font-bold text-slate-800 mb-1">
                    {isTracking ? 'Trip in Progress' : 'Ready for Departure'}
                  </h2>
                  <p className="text-slate-500">
                    {isTracking ? 'Currently capturing your travel data...' : 'Start tracking your journey to see AI insights'}
                  </p>
                </div>
                {isTracking && (
                  <motion.div 
                    initial={{ opacity: 0, scale: 0.5 }}
                    animate={{ opacity: 1, scale: 1 }}
                    className="flex items-center gap-2 bg-emerald-50 text-emerald-700 px-4 py-1.5 rounded-full text-sm font-bold border border-emerald-100"
                  >
                    <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse" />
                    LIVE
                  </motion.div>
                )}
              </div>

              <div className="grid grid-cols-2 md:grid-cols-4 gap-6 mb-10">
                <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                  <span className="text-xs font-bold text-slate-400 uppercase tracking-wider block mb-1">Duration</span>
                  <p className="text-2xl font-mono font-bold text-slate-700">{formatDuration(duration)}</p>
                </div>
                <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                  <span className="text-xs font-bold text-slate-400 uppercase tracking-wider block mb-1">Points</span>
                  <p className="text-2xl font-mono font-bold text-slate-700">{currentTrip?.locations.length || 0}</p>
                </div>
                <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                  <span className="text-xs font-bold text-slate-400 uppercase tracking-wider block mb-1">Accuracy</span>
                  <p className="text-2xl font-mono font-bold text-slate-700">
                    {currentTrip && currentTrip.locations.length > 0
                      ? (currentTrip.locations[currentTrip.locations.length - 1].accuracy || 0).toFixed(0)
                      : 0}m
                  </p>
                </div>
                 <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                  <span className="text-xs font-bold text-slate-400 uppercase tracking-wider block mb-1">Status</span>
                  <p className={`text-xl font-bold ${isTracking ? 'text-emerald-600' : 'text-slate-400'}`}>
                    {isTracking ? 'Active' : 'Idle'}
                  </p>
                </div>
              </div>

              <div className="flex gap-4">
                {!isTracking ? (
                  <button 
                    onClick={handleStart}
                    className="flex-1 bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-4 rounded-2xl shadow-lg shadow-indigo-100 transition-all flex items-center justify-center gap-2 group"
                  >
                    <Play className="w-5 h-5 fill-current group-hover:scale-110 transition-transform" />
                    Start Tracking Trip
                  </button>
                ) : (
                  <div className="flex-1 flex flex-col gap-3">
                    <button 
                      onClick={handleStop}
                      className={cn(
                        "flex-1 font-bold py-4 rounded-2xl shadow-lg transition-all flex items-center justify-center gap-2",
                        showStopConfirmation 
                          ? "bg-amber-500 hover:bg-amber-600 text-white shadow-amber-100" 
                          : "bg-rose-500 hover:bg-rose-600 text-white shadow-rose-100"
                      )}
                    >
                      {showStopConfirmation ? (
                        <CheckCircle className="w-5 h-5 fill-current" />
                      ) : (
                        <Square className="w-5 h-5 fill-current" />
                      )}
                      {showStopConfirmation ? 'Confirm Stop' : 'Stop & Finish'}
                    </button>
                    {showStopConfirmation && (
                      <button 
                        onClick={() => setShowStopConfirmation(false)}
                        className="text-slate-400 text-xs font-bold uppercase tracking-widest hover:text-slate-600 transition-colors"
                      >
                        Cancel
                      </button>
                    )}
                  </div>
                )}
              </div>
            </div>
          </section>

          {/* Activity Section */}
          <section className="space-y-4">
            <div className="flex items-center justify-between">
               <h3 className="text-lg font-bold text-slate-700 flex items-center gap-2">
                <History className="w-5 h-5 text-indigo-500" />
                Recent Journeys
              </h3>
              <Link href="/history">
                <button className="text-sm font-medium text-indigo-600 hover:underline">View All</button>
              </Link>
            </div>

            <div className="space-y-4">
              <AnimatePresence>
                {trips.length === 0 ? (
                  <div className="text-center py-12 bg-white rounded-3xl border border-slate-200 border-dashed">
                    <p className="text-slate-400">No trips recorded yet.</p>
                  </div>
                ) : (
                  trips.map((trip) => (
                    <Link 
                      key={trip.id}
                      href={`/trip/${trip.id}`}
                      className="block group"
                    >
                      <motion.div 
                        initial={{ opacity: 0, y: 20 }}
                        animate={{ opacity: 1, y: 0 }}
                        className="bg-white p-5 rounded-2xl border border-slate-200 hover:border-indigo-200 hover:shadow-md transition-all flex items-center gap-4 cursor-pointer"
                      >
                        <div className="bg-slate-100 p-3 rounded-xl group-hover:bg-indigo-50 transition-colors">
                          {trip.predictedMode === 'walking' && <span className="text-2xl">=ƒÜ¦</span>}
                          {trip.predictedMode === 'cycling' && <span className="text-2xl">=ƒÜ¦</span>}
                          {trip.predictedMode === 'driving' && <span className="text-2xl">=ƒÜù</span>}
                          {trip.predictedMode === 'public_transport' && <span className="text-2xl">=ƒÜî</span>}
                          {(!trip.predictedMode || trip.predictedMode === 'unknown') && <span className="text-2xl">=ƒôì</span>}
                        </div>
                        <div className="flex-1">
                          <div className="flex justify-between items-start">
                            <h4 className="font-bold text-slate-800 capitalize">
                              {trip.predictedMode || 'Unknown Trip'}
                            </h4>
                            <span className="text-xs font-bold text-slate-400">
                              {new Date(trip.startTime).toLocaleDateString()}
                            </span>
                          </div>
                          <div className="flex items-center gap-4 text-sm text-slate-500 mt-1">
                            <span className="flex items-center gap-1"><Clock className="w-3.5 h-3.5" /> {(trip.duration! / 60000).toFixed(0)} mins</span>
